noncompliant:
__attribute__((returns_nonnull)) int* func() {
  return NULL; // Noncompliant: returning null from returns_nonnull function
}

void process(__attribute__((nonnull)) char* str) {
  // Noncompliant: not checking if str is null
  printf("%s", str);
}
void caller() {
  process(NULL); // Noncompliant: passing null to nonnull parameter
}

compliant:
__attribute__((returns_nonnull)) int* make_array(size_t len) {
  int* arr = malloc(len * sizeof(int));
  if (arr == NULL) {
    exit(1); // Compliant: ensure non-null return
  }
  return arr;
}

void process(__attribute__((nonnull)) char* str) {
  // Compliant: function assumes str is not null
  printf("%s", str);
}
void caller() {
  char* valid_str = "hello";
  process(valid_str); // Compliant: passing valid non-null pointer
}
